-			break;
-		error = _detach_handler(&_p[i]);
-		if (error != 0)
-			break;
+	while (p->dir != NODIR) {
+		TAILQ_REMOVE(&handler_chain, p, link);
+		p++;
 	}
-	LIBALIAS_WUNLOCK();
-	return (error);
-}
